<?php $pdo = new PDO("sqlite:" . __DIR__ . "/ecommerce.db"); $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION); try { $pdo->exec("ALTER TABLE users ADD COLUMN otp_code TEXT"); echo "Added otp_code\n"; } catch (Exception $e) { echo $e->getMessage() . "\n"; } try { $pdo->exec("ALTER TABLE users ADD COLUMN otp_expires_at TEXT"); echo "Added otp_expires_at\n"; } catch (Exception $e) { echo $e->getMessage() . "\n"; } try { $pdo->exec("ALTER TABLE users ADD COLUMN google_id TEXT"); echo "Added google_id\n"; } catch (Exception $e) { echo $e->getMessage() . "\n"; }
